129	     * @returns Promise 預中效果完成的 Promise
130	     */
131	    private async CheckPreWinEffect( prevSpinAckVersion: number ): Promise<void> {
132	        this.m_isPreWinEffectPlayed = true;
133	        const currentIndex = this.m_gameView.CurPlateIndex;
134	
135	        if ( this.m_gameView.PreWinHandledIndex === currentIndex )
136	        {
137	            // OnRecvSpinAck 已為此 index 觸發動畫（Base Game 正常流程 / Unshow）
138	            // 直接等待該動畫結束即可
139	            await this.m_gameView.PreWinAnimPromise;
140	        }
141	        else if ( !this.m_gameView.IsFreeGame && !this.m_gameView.IsRespinGame )
142	        {
143	            // Base Game：OnRecvSpinAck 尚未到達，等待本局新的 SpinAck
144	            // 用版本號判斷，避免誤讀上一局的舊 SpinAck
145	            await WaitUntil( () => this.m_gameView.SpinAckVersion > prevSpinAckVersion );
146	            // OnRecvSpinAck 已設定 PreWinAnimPromise（有宣告時為動畫 Promise，否則為立即 resolve）
147	            await this.m_gameView.PreWinAnimPromise;
148	        }
149	        else
150	        {
151	            // FG / Respin 後續回合：SpinAck 資料已在首輪一次性到達，直接讀取
152	            if ( currentIndex < 0 )
153	            {
154	                error( "currentIndex is less than 0" );
155	            }
156	            const nowRound = this.m_gameView.SpinAck?.RoundQueue?.[ currentIndex ];
157	            if ( nowRound && nowRound.MysteryEventKind > 0 )
158	            {
159	                await this.PlayPreWinEffect( nowRound.MysteryEventKind );
160	            }
161	        }
162	
163	        this.m_isPreWinEffectPlayed = false;
164	    }
