19	const { ccclass } = _decorator;
20	
21	// 進入免費遊戲狀態前的初始等待時間
22	const ENTER_FREE_INITIAL_DELAY_SECONDS = 1.5;
23	
24	// 輪盤初始化後，開始後續流程前的等待時間
25	const GOLD_BLITZ_ROULETTE_INIT_DELAY_SECONDS = 0.5;
26	
27	// 輪盤進場前，隱藏其他 UI 的延遲時間
28	const GOLD_BLITZ_ROULETTE_HIDE_OTHER_UI_DELAY_SECONDS = 0.5;
29	
30	// 輪盤完成後，重新顯示其他 UI 的延遲時間
31	const GOLD_BLITZ_ROULETTE_SHOW_OTHER_UI_DELAY_SECONDS = 3;
32	
33	// 現金飛分演出次數
34	const FREE_GAME_ADD_CASH_ANIMATION_COUNT = 15;
35	
36	// 現金飛分演出的目標索引
37	const FREE_GAME_ADD_CASH_ANIMATION_TARGET_INDEXES = [0, 1, 2, 3, 4, 5];
38	
39	// 現金飛分演出的每次間隔時間
40	const FREE_GAME_ADD_CASH_ANIMATION_INTERVAL_SECONDS = 0.1;
