42	/**@ch EnterFreeState 狀態機階段*/
43	enum EnterFreeStatePhase {
44	    IDLE = 0,                      // 初始狀態
45	    SPINNING = 1,                  // 轉輪旋轉中，等待演出完成
46	    COMPLETED = 2                  // 轉輪停止，演出完成，準備跳轉
47	}
