49	@ccclass( "EnterFreeState" )
50	export class EnterFreeState extends BaseState
51	{
52	    private m_gameView: GameView = null;
53	
54	    /**@ch 是否播放輪盤完成*/
55	    private m_isPlayGoldBlitzRouletteFinish: boolean = false;
56	
57	    /**@ch 當前狀態階段*/
58	    private m_phase: EnterFreeStatePhase = EnterFreeStatePhase.IDLE;
59	
60	    /**@ch 倍率演出是否完成*/
61	    private m_isMultiplierAnimFinish: boolean = false;
62	
63	    /**@ch 現金演出是否完成*/
64	    private m_isCashAnimFinish: boolean = false;
65	
66	    constructor( gameView: GameView )
67	    {
68	        super();
69	        this.m_gameView = gameView;
70	    }
71	
72	    public async OnEnter()
73	    {
74	        log( "OnEnter State : ENTER_FREE" );
75	
76	        await Define.Wait(this.m_gameView, ENTER_FREE_INITIAL_DELAY_SECONDS);
77	
78	        // 暫停主遊戲背景音樂
79	        this.m_gameView.PauseMainGameBgm();
80	
81	        newBottombarManager.SetEnterFree();
82	        this.StopEffect();
83	        this.m_gameView.IsFreeGame = true;
84	
85	        newBottombarManager.SetBarNodeVisiable( false );
86	        this.m_gameView.BuyBonus?.SetBuyBtnVisible( false );        
87	
88	        // 鎖定方向
89	        Common.SetLockOrientation(true);
90	
91	        // 播放輪盤
92	        await this.PlayGoldBlitzRoulette();
93	
94	        // 播放免費遊戲音樂
95	        this.m_gameView.PlayFreeGameBgm();
96	
97	        // 準備進入免費遊戲
98	        newBottombarManager.SetBarNodeVisiable(true);
99	
100	        // 顯示免費遊戲回合數字
101	        eventManager.Dispatch(FREE_GAME_ROUND_UI_EVENT.SHOW);
102	
103	        // 開始Spin
104	        // 注意：EnterFreeState 進入時 CurPlateIndex 仍是 main game 的值，但要播的是 FreeGame round 1。
105	        // 顯式傳入 +1 偏移取得正確的 fileIndex（與 SetRealPlateInfo 用 CurPlateIndex+1 取資料的語意對齊）。
106	        // this.m_gameView.StartSpin(this.m_gameView.SlotReels.ResolveFakeReelFileIndex(1));
107	
108	        // 設定所有轉輪符號顯示模式為只顯示Blank
109	        this.m_gameView.SetAllReelSymbolMode( ReelSymbolMode.OnlyBlank );
110	        this.m_gameView.SetSlotReelCanPlaySymbolAudio( false );
111	
112	        // 初始化狀態標誌
113	        this.m_isMultiplierAnimFinish = false;
114	        this.m_isCashAnimFinish = false;
115	        this.m_phase = EnterFreeStatePhase.SPINNING;
116	
117	        // 播放免費遊戲加倍演出，完成後才開始現金演出
118	        void this.PlayFreeGameAddMultiplierAnim().then(() => {
119	            if ( !this.m_gameView?.node?.isValid ) return;
120	            this.m_isMultiplierAnimFinish = true;
121	
122	            // 倍率演出完成後，才開始現金演出
123	            void this.PlayFreeGameAddCashAnim().then(() => {
124	                if ( !this.m_gameView?.node?.isValid ) return;
125	                this.m_isCashAnimFinish = true;
126	            }).catch( e => console.warn( "[EnterFreeState] PlayFreeGameAddCashAnim error:", e ) );
127	        }).catch( e => console.warn( "[EnterFreeState] PlayFreeGameAddMultiplierAnim error:", e ) );
128	    }
129	
130	    public OnProcess( dt: number = 0 )
131	    {
132	        // 只有在 SPINNING 狀態才需要處理
133	        if ( this.m_phase !== EnterFreeStatePhase.SPINNING )
134	        {
135	            return;
136	        }
137	
138	        // 更新轉輪旋轉
139	        this.m_gameView.SlotReels.Spin( dt );
140	
141	        // 檢查演出是否全部完成
142	        if ( !this.m_isMultiplierAnimFinish || !this.m_isCashAnimFinish )
143	        {
144	            // 演出未完成，持續旋轉
145	            return;
146	        }
147	
148	        // 取消 FlyManager AddCash 延遲 callback（避免晚到 callback 在下一行 Normal 設定後把 col 改回 CashAndBlank）
149	        eventManager.Dispatch( FLY_EVENT.CANCEL_ADD_CASH_ANIMATION );
150	
151	        // 演出剛結束，切回 Normal 符號模式（BC-5；轉動中切換，1-frame 內可能有符號突現，Phase 4 dev preview 觀察重點）
152	        this.m_gameView.SetAllReelSymbolMode( ReelSymbolMode.Normal );
153	
154	        this.m_phase = EnterFreeStatePhase.COMPLETED;
155	
156	        // 處理 AutoSpin UI（移除原 SetSpinState(IDLE)，SpinState.OnEnter 會自行設 START_SPIN）
157	        if ( newBottombarManager.IsAutoSpin && this.m_gameView.AutoplayInfos.isCheckFree )
158	        {
159	            newBottombarManager.ShowAutoPlayState( false );
160	        }
161	
162	        // BC-2：統一設 IsFirstRound=false → RoundEndState.ForEndToNext 走 SPIN 分支（不再 IDLE 等點擊）
163	        this.m_gameView.IsFirstRound = false;
164	
165	        // BC-3：請 RoundEndState 跳過 0.5s noWin 緩衝（讀完即清，見 RoundEndState.OnEnter）
166	        this.m_gameView.SkipFreeGameNoWinDelay = true;
167	
168	        // BC-7：請 SpinState 對 SlotReels.StartSpin 傳 continueSpin=true（保留時間軸與 ColumnSymbol 視覺位置同步）
169	        this.m_gameView.IsFreeGameFirstSpinContinuous = true;
170	
171	        // 跳轉到下一個狀態
172	        stateManager.NextState( Game_Define.GameState.ROUND_END );
173	    }
174	
175	    public OnLeave()
176	    {
177	        this.m_gameView.SetAllReelSymbolMode( ReelSymbolMode.Normal );
178	        this.m_gameView.SetSlotReelCanPlaySymbolAudio( true );
179	
180	        eventManager.UnRegister( GOLD_BLITZ_ROULETTE_EVENT.ROTATE_COMPLETE, this );
181	
182	        // 重置狀態標誌
183	        this.m_phase = EnterFreeStatePhase.IDLE;
184	        this.m_isMultiplierAnimFinish = false;
185	        this.m_isCashAnimFinish = false;
186	        this.m_isPlayGoldBlitzRouletteFinish = false;
187	
188	        // 解除鎖定
189	        Common.SetLockOrientation(false);
190	    }
