192	    /**
193	     * @ch 停止效果
194	     */
195	    private StopEffect()
196	    {
197	        this.m_gameView.EffectPlate.StopOneLineShow();
198	        this.m_gameView.ClearAll();
199	        this.m_gameView.EffectPlate.CurAwardLines.length = 0;
