60	    /**
61	     * @ch 處理轉輪
62	     */
63	    private HandleReel(): void
64	    {
65	        // 設定Respin鎖定列的旋轉鎖定
66	        Game_Define.RespinLockColumns.forEach( column => {
67	            this.m_gameView.SlotReels.SetColumnLock( column, true );
68	        } );
69	
70	        // 鎖定特定位置
71	        const nextRound = this.m_gameView.SpinAck.RoundQueue[this.m_gameView.CurPlateIndex + 1];
72	        const plateSymbol = ( nextRound?.FreePlateSymbol && nextRound.FreePlateSymbol.length > 0 )
73	            ? nextRound.FreePlateSymbol
74	            : nextRound?.MainPlateSymbol;
75	        nextRound?.RespinLockedPos?.forEach( ( serverPos: number ) =>
76	        {
77	            const decoded = Common.DecodeServerPosByRowConfig( serverPos );
78	            if ( !decoded )
79	            {
80	                console.warn( `[EnterRespinState] 無法解碼 RespinLockedPos: ${serverPos}` );
81	                return;
82	            }
83	
84	            const col = decoded.col;
85	            const row = decoded.row;
86	            const symbol = plateSymbol?.[ col ]?.Col?.[ row ]?.Symbol ?? -1;
87	            const number = plateSymbol?.[ col ]?.Col?.[ row ]?.Number ?? -1;
88	            if ( symbol < 0 )
89	            {
90	                console.warn( `[EnterRespinState] 找不到鎖定位置 Symbol: pos=${serverPos} => (${col},${row})` );
91	                return;
92	            }
93	
94	            console.log( `[EnterRespinState] 鎖定位置: pos=${serverPos} => (${col},${row}), symbol=${symbol}` );
95	
96	            // CollectAndRetrigger 在 Respin 鎖定時顯示為 Collect 靜態張
97	            const displaySymbol = ( symbol === Game_Define.Symbol.CollectAndRetrigger )
98	                ? Game_Define.Symbol.Collect
99	                : symbol;
100	
101	            // 清掉該位置殘留的 Spine 節點（停輪時建立的），避免蓋住靜態張
102	            this.m_gameView.EffectPlate.CleanSymbolSpineAt( col, row, Game_Define.LAYERS.TWO, false );
103	
104	            // 關閉原本格子的靜態圖，改用 EffectPlate 疊一張靜態圖
105	            this.m_gameView.SlotReels.AllColumns?.[ Game_Define.MIDDLE_PLATE_INDEX ]?.[ col ]?.HideSymbolByRow( row );
106	            this.m_gameView.EffectPlate.CreateSymbolStaticNode( col, row, displaySymbol, number);
107	        } );
108	    }
