337	        if ( !content || !Array.isArray( content ) )
338	        {
339	            return [];
340	        }
341	
342	        let realPlate: protocol.ar2es2Proto.CColumn[] = [];
343	        for ( let i = 0; i < content.length; i++ )
344	        {
345	            if ( content[ i ] )
346	            {
347	                let column = new protocol.ar2es2Proto.CColumn( content[ i ] );
