402	    ConvertDemoAck( ack: protocol.ar2es2Proto.ISpinAck, targetBet: number )
403	    {
404	        if ( !ack )
405	            return;
406	
407	        const winScale = targetBet / ack.Bet;
408	        if ( winScale != 1 )
409	        {
410	            ack.Bet = targetBet;
411	            ack.FreeTotalWin = tools.times( ack.FreeTotalWin, winScale );
412	            ack.TotalWin = tools.times( ack.TotalWin, winScale );
413	            ack.RoundQueue.forEach( roundInfo =>
414	            {
415	                roundInfo.RoundWin = tools.times( roundInfo.RoundWin, winScale );
416	                roundInfo.PlateQueue?.forEach( plateInfo =>
417	                {
418	                    plateInfo.AwardDataVec?.forEach( adv => { adv.Win = tools.times( adv.Win, winScale ); } );
419	                    plateInfo.PlateSymbol?.forEach( column => { column.Col?.forEach( symbol => { if ( symbol.Number > 0 ) symbol.Number = tools.times( symbol.Number, winScale ); } ); } );
420	                } );
421	            } );
422	        }
423	    }
